// Parse the Python script output
const stdout = $input.item.json.stdout;
const parsedOutput = JSON.parse(stdout);

return {
  json: parsedOutput
};

// Prepare context for AI summarization
const data = $input.item.json;
const messages = data.messages || [];

// Cap messages for token limits (100 messages for AI)
const maxMessagesForAI = 100;
const messagesToSummarize = messages.slice(0, maxMessagesForAI);

// Create structured context for Gemini
let context = `You are analyzing ${data.totalMatches} Telegram messages matching specific keywords across ${data.chatsSearched} chats.\n\n`;

context += `MESSAGES (showing ${messagesToSummarize.length} of ${data.totalMatches}):\n\n`;

messagesToSummarize.forEach((msg, idx) => {
  context += `[${idx + 1}] Chat: ${msg.chat_name}\n`;
  context += `Author: ${msg.author} | Time: ${msg.timestamp}\n`;
  context += `Text: ${msg.text}\n\n`;
});

if (data.totalMatches > maxMessagesForAI) {
  context += `\⚠️ Summary truncated: Showing first ${maxMessagesForAI} of ${data.totalMatches} total matches due to token limits.\n`;
}

return {
  json: {
    context: context,
    messageCount: messagesToSummarize.length,
    totalMessages: data.totalMatches,
    isTruncated: data.totalMatches > maxMessagesForAI,
    metadata: data
  }
};

// Format final output with summary, messages table, and counters
const aiOutput = $('AI Summary Agent').item.json.output;
const contextData = $('Prepare AI Context').item.json;
const metadata = contextData.metadata;
const messages = metadata.messages || [];
const isTruncated = contextData.isTruncated;

// Build AI-generated summary section
let summary = '## AI-Generated Summary\n\n';
summary += aiOutput + '\n\n';

if (isTruncated) {
  summary += '⚠️ **Note:** Summary based on first 100 messages due to token limits.\n\n';
}

// Build statistics counters
let counters = '### Search Statistics\n\n';
counters += `- **Chats Searched:** ${metadata.chatsSearched}\n`;
counters += `- **Total Matches Found:** ${metadata.totalMatches}\n`;
counters += `- **Messages Summarized:** ${Math.min(metadata.totalMatches, 100)}\n\n`;

// Build chat breakdown
if (metadata.chatCounts && Object.keys(metadata.chatCounts).length > 0) {
  counters += '### Matches per Chat\n\n';
  for (const [chatName, count] of Object.entries(metadata.chatCounts)) {
    counters += `- **${chatName}:** ${count} messages\n`;
  }
  counters += '\n';
}

// Build error notices (if any)
let errors = '';
if (metadata.errors && metadata.errors.length > 0) {
  errors = '### ⚠️ Errors\n\n';
  metadata.errors.forEach(err => {
    errors += `- **${err.chat}:** ${err.error}\n`;
  });
  errors += '\n';
}

// Build messages table
let messagesTable = '## Matched Messages\n\n';
messagesTable += '| Chat | Author | Timestamp | Snippet | Link |\n';
messagesTable += '|------|--------|-----------|---------|------|\n';

messages.forEach(msg => {
  const snippet = msg.snippet.replace(/\|/g, '\\|').replace(/\n/g, ' ');
  messagesTable += `| ${msg.chat_name} | ${msg.author} | ${msg.timestamp} | ${snippet} | [View](${msg.telegram_link}) |\n`;
});

return {
  json: {
    summary: summary,
    counters: counters,
    errors: errors,
    messagesTable: messagesTable,
    fullOutput: summary + counters + errors + messagesTable,
    rawData: {
      messages: messages,
      totalMatches: metadata.totalMatches,
      chatsSearched: metadata.chatsSearched,
      chatCounts: metadata.chatCounts
    }
  }
};
